'use client'
import { useState } from 'react'

export function CheckoutModal({ total }: { total: number }) {
  const [open, setOpen] = useState(false)
  const [method, setMethod] = useState<'cash' | 'card' | 'ewallet' | null>(null)

  return (
    <>
      <button 
        onClick={() => setOpen(true)} 
        className="w-full neumorphic-flat hover:neumorphic-pressed px-4 py-3 rounded-lg font-semibold transition-all"
      >
        Checkout ${total.toFixed(2)}
      </button>
      
      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40" onClick={() => setOpen(false)}>
          <div className="neumorphic p-6 w-full max-w-md" onClick={e => e.stopPropagation()}>
            <div className="text-lg font-semibold text-primary mb-4">Select Payment</div>
            <div className="grid grid-cols-3 gap-3">
              {['cash', 'card', 'ewallet'].map(m => (
                <button 
                  key={m} 
                  onClick={() => setMethod(m as any)} 
                  className={`neumorphic-flat p-3 capitalize transition-all ${
                    method === m ? 'bg-accent text-white shadow-inner' : 'hover:neumorphic-pressed'
                  }`}
                >
                  {m}
                </button>
              ))}
            </div>
            <div className="mt-6 flex items-center justify-end gap-3">
              <button 
                onClick={() => setOpen(false)} 
                className="neumorphic-flat px-4 py-2 rounded-lg hover:neumorphic-pressed transition-all"
              >
                Cancel
              </button>
              <button 
                disabled={!method} 
                className={`px-4 py-2 rounded-lg font-semibold transition-all ${
                  method 
                    ? 'bg-accent text-white shadow-inner hover:bg-blue-600' 
                    : 'neumorphic-inset text-muted cursor-not-allowed'
                }`}
              >
                {method ? 'Confirm' : 'Choose method'}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  )
}